script:
frappe.ui.form.on("Student ID Card Batch", {
    refresh(frm) {

        // Fetch Students Button
        frm.add_custom_button("Fetch Students", function () {
            fetch_students(frm);
        });

        // Generate Cards Button
        frm.add_custom_button("Generate Cards", function () {
            generate_cards(frm);
        });

    }
});

function fetch_students(frm) {

    if (!frm.doc.academic_year) {
        frappe.msgprint("Please select Academic Year.");
        return;
    }

    if (!frm.doc.program) {
        frappe.msgprint("Please select Program.");
        return;
    }

    frappe.call({
        method: "frappe.client.get_list",
        args: {
            doctype: "Custom Student",
            filters: {
                current_academic_year: frm.doc.academic_year,
                current_program: frm.doc.program,
                enrollment_status: "Enrolled"
            },
            fields: [
                "name",
                "student_name",
                "roll_no"
            ],
            limit_page_length: 1000
        },

        callback: function(r) {

            frm.clear_table("students");

            (r.message || []).forEach(function(student) {

                let row = frm.add_child("students");

                row.student = student.name;
                row.student_name = student.student_name;
                row.roll_no = student.roll_no;

            });

            frm.refresh_field("students");

            frappe.show_alert({
                message: __("Students Fetched Successfully"),
                indicator: "green"
            });

        }
    });

}


// Generate Cards
function generate_cards(frm) {

    if (!frm.doc.students || frm.doc.students.length === 0) {
        frappe.msgprint("Please fetch students first.");
        return;
    }

    if (!frm.doc.name) {
        frappe.msgprint("Please save the Batch before generating ID Cards.");
        return;
    }

    frappe.call({
        method: "generate_student_id_cards",
        args: {
            batch: frm.doc.name
        },
        freeze: true,
        freeze_message: "Generating Student ID Cards...",
        callback: function(r) {

            frm.reload_doc();

            if (r.message) {
                frappe.msgprint(r.message);
            }

        }
    });

}
